import{_ as r}from"./plugin-vue_export-helper.21dcd24c.js";import{d as a}from"./app.731f1ea1.js";const e={},o=a('<h1 id="\u6D4F\u89C8\u5668\u57FA\u7840" tabindex="-1"><a class="header-anchor" href="#\u6D4F\u89C8\u5668\u57FA\u7840" aria-hidden="true">#</a> \u6D4F\u89C8\u5668\u57FA\u7840</h1><h2 id="\u8FDB\u7A0B\u548C\u7EBF\u7A0B" tabindex="-1"><a class="header-anchor" href="#\u8FDB\u7A0B\u548C\u7EBF\u7A0B" aria-hidden="true">#</a> \u8FDB\u7A0B\u548C\u7EBF\u7A0B</h2><p>\u4E0D\u8FC7\uFF0C\u5728\u4ECB\u7ECD\u8FDB\u7A0B\u548C\u7EBF\u7A0B\u4E4B\u524D\uFF0C\u6211\u9700\u8981\u5148\u8BB2\u89E3\u4E0B\u4EC0\u4E48\u662F\u5E76\u884C\u5904\u7406\uFF0C\u56E0\u4E3A\u5982\u679C\u4F60\u7406\u89E3\u4E86\u5E76\u884C\u5904\u7406\u7684\u6982\u5FF5\uFF0C\u90A3\u4E48\u518D\u7406\u89E3\u8FDB\u7A0B\u548C\u7EBF\u7A0B\u4E4B\u95F4\u7684\u5173\u7CFB\u5C31\u4F1A\u53D8\u5F97\u8F7B\u677E\u8BB8\u591A\u3002</p><h3 id="\u4EC0\u4E48\u662F\u5E76\u884C\u5904\u7406" tabindex="-1"><a class="header-anchor" href="#\u4EC0\u4E48\u662F\u5E76\u884C\u5904\u7406" aria-hidden="true">#</a> \u4EC0\u4E48\u662F\u5E76\u884C\u5904\u7406</h3><p>\u8BA1\u7B97\u673A\u4E2D\u7684\u5E76\u884C\u5904\u7406\u5C31\u662F\u540C\u4E00\u65F6\u523B\u5904\u7406\u591A\u4E2A\u4EFB\u52A1\uFF0C\u6BD4\u5982\u6211\u4EEC\u8981\u8BA1\u7B97\u4E0B\u9762\u8FD9\u4E09\u4E2A\u8868\u8FBE\u5F0F\u7684\u503C\uFF0C\u5E76\u663E\u793A\u51FA\u7ED3\u679C</p><h3 id="\u7EBF\u7A0B-vs-\u8FDB\u7A0B" tabindex="-1"><a class="header-anchor" href="#\u7EBF\u7A0B-vs-\u8FDB\u7A0B" aria-hidden="true">#</a> \u7EBF\u7A0B VS \u8FDB\u7A0B</h3><p>\u4E00\u4E2A\u8FDB\u7A0B\u5C31\u662F\u4E00\u4E2A\u7A0B\u5E8F\u7684\u8FD0\u884C\u5B9E\u4F8B\u3002\u8BE6\u7EC6\u89E3\u91CA\u5C31\u662F\uFF0C\u542F\u52A8\u4E00\u4E2A\u7A0B\u5E8F\u7684\u65F6\u5019\uFF0C\u64CD\u4F5C\u7CFB\u7EDF\u4F1A\u4E3A\u8BE5\u7A0B\u5E8F\u521B\u5EFA\u4E00\u5757\u5185\u5B58\uFF08\u6700\u5C0F\u5185\u5B58\u5206\u914D\u5355\u5143\uFF09\uFF0C\u7528\u6765\u5B58\u653E\u4EE3\u7801\u3001\u8FD0\u884C\u4E2D\u7684\u6570\u636E\u548C\u4E00\u4E2A\u6267\u884C\u4EFB\u52A1\u7684\u4E3B\u7EBF\u7A0B\uFF0C\u6211\u4EEC\u628A\u8FD9\u6837\u7684\u4E00\u4E2A\u8FD0\u884C\u73AF\u5883\u53EB\u8FDB\u7A0B\u3002</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/3380f0a16c323deda5d3a300804b95da.png" alt="" loading="lazy"></p><p>\u4ECE\u56FE\u4E2D\u53EF\u4EE5\u770B\u5230\uFF0C\u7EBF\u7A0B\u662F\u4F9D\u9644\u4E8E\u8FDB\u7A0B\u7684\uFF0C\u800C\u8FDB\u7A0B\u4E2D\u4F7F\u7528\u591A\u7EBF\u7A0B\u5E76\u884C\u5904\u7406\u80FD\u63D0\u5347\u8FD0\u7B97\u6548\u7387\u3002</p><p>\u603B\u7ED3\u6765\u8BF4\uFF0C\u8FDB\u7A0B\u548C\u7EBF\u7A0B\u4E4B\u95F4\u7684\u5173\u7CFB\u6709\u4EE5\u4E0B4\u4E2A\u7279\u70B9</p><p><strong>1. \u8FDB\u7A0B\u4E2D\u7684\u4EFB\u610F\u4E00\u7EBF\u7A0B\u6267\u884C\u51FA\u9519\uFF0C\u90FD\u4F1A\u5BFC\u81F4\u6574\u4E2A\u8FDB\u7A0B\u7684\u5D29\u6E83\u3002</strong></p><p><strong>2. \u7EBF\u7A0B\u4E4B\u95F4\u5171\u4EAB\u8FDB\u7A0B\u4E2D\u7684\u6570\u636E\u3002</strong></p><p>\u7EBF\u7A0B\u4E4B\u95F4\u53EF\u4EE5\u5BF9\u8FDB\u7A0B\u7684\u516C\u5171\u6570\u636E\u8FDB\u884C\u8BFB\u5199\u64CD\u4F5C\u3002</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/d0efacd7f299ed99e776cb97da2a799e.png" alt="" loading="lazy"></p><p><strong>3. \u5F53\u4E00\u4E2A\u8FDB\u7A0B\u5173\u95ED\u4E4B\u540E\uFF0C\u64CD\u4F5C\u7CFB\u7EDF\u4F1A\u56DE\u6536\u8FDB\u7A0B\u6240\u5360\u7528\u7684\u5185\u5B58\u3002</strong></p><p><strong>4. \u8FDB\u7A0B\u4E4B\u95F4\u7684\u5185\u5BB9\u76F8\u4E92\u9694\u79BB\u3002</strong></p><h2 id="\u5355\u8FDB\u7A0B\u6D4F\u89C8\u5668\u65F6\u4EE3" tabindex="-1"><a class="header-anchor" href="#\u5355\u8FDB\u7A0B\u6D4F\u89C8\u5668\u65F6\u4EE3" aria-hidden="true">#</a> \u5355\u8FDB\u7A0B\u6D4F\u89C8\u5668\u65F6\u4EE3</h2><p>\u5728\u4E86\u89E3\u4E86\u8FDB\u7A0B\u548C\u7EBF\u7A0B\u4E4B\u540E\uFF0C\u6211\u4EEC\u518D\u6765\u4E00\u8D77\u770B\u4E0B\u5355\u8FDB\u7A0B\u6D4F\u89C8\u5668\u7684\u67B6\u6784\u3002\u987E\u540D\u601D\u4E49\uFF0C\u5355\u8FDB\u7A0B\u6D4F\u89C8\u5668\u662F\u6307\u6D4F\u89C8\u5668\u7684\u6240\u6709\u529F\u80FD\u6A21\u5757\u90FD\u662F\u8FD0\u884C\u5728\u540C\u4E00\u4E2A\u8FDB\u7A0B\u91CC\uFF0C\u8FD9\u4E9B\u6A21\u5757\u5305\u542B\u4E86\u7F51\u7EDC\u3001\u63D2\u4EF6\u3001JavaScript\u8FD0\u884C\u73AF\u5883\u3001\u6E32\u67D3\u5F15\u64CE\u548C\u9875\u9762\u7B49\u3002\u5176\u5B9E\u65E9\u57282007\u5E74\u4E4B\u524D\uFF0C\u5E02\u9762\u4E0A\u6D4F\u89C8\u5668\u90FD\u662F\u5355\u8FDB\u7A0B\u7684\u3002\u5355\u8FDB\u7A0B\u6D4F\u89C8\u5668\u7684\u67B6\u6784\u5982\u4E0B\u56FE\u6240\u793A</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/6ddad2419b049b0eb2a8036f3dfff1ca.png" alt="" loading="lazy"></p><h3 id="\u76EE\u524D\u591A\u8FDB\u7A0B\u67B6\u6784" tabindex="-1"><a class="header-anchor" href="#\u76EE\u524D\u591A\u8FDB\u7A0B\u67B6\u6784" aria-hidden="true">#</a> \u76EE\u524D\u591A\u8FDB\u7A0B\u67B6\u6784</h3><p>\u4E0D\u8FC7Chrome\u7684\u53D1\u5C55\u662F\u6EDA\u6EDA\u5411\u524D\u7684\uFF0C\u76F8\u8F83\u4E4B\u524D\uFF0C\u76EE\u524D\u7684\u67B6\u6784\u53C8\u6709\u4E86\u5F88\u591A\u65B0\u7684\u53D8\u5316\u3002\u6211\u4EEC\u5148\u770B\u770B\u6700\u65B0\u7684Chrome\u8FDB\u7A0B\u67B6\u6784\uFF0C\u4F60\u53EF\u4EE5\u53C2\u8003\u4E0B\u56FE</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/b61cab529fa31301bde290813b4587fc.png" alt="" loading="lazy"></p><p>\u4ECE\u56FE\u4E2D\u53EF\u4EE5\u770B\u51FA\uFF0C\u6700\u65B0\u7684Chrome\u6D4F\u89C8\u5668\u5305\u62EC\uFF1A<strong><u>1\u4E2A\u6D4F\u89C8\u5668\uFF08Browser\uFF09\u4E3B\u8FDB\u7A0B\u30011\u4E2A GPU \u8FDB\u7A0B\u30011\u4E2A\u7F51\u7EDC\uFF08NetWork\uFF09\u8FDB\u7A0B\u3001\u591A\u4E2A\u6E32\u67D3\u8FDB\u7A0B\u548C\u591A\u4E2A\u63D2\u4EF6\u8FDB\u7A0B</u></strong></p><p><strong>\u4E3B\u3001G\u3001\u7F51\u3001\u6E32\u63D2</strong></p><p>\u4E0B\u9762\u6211\u4EEC\u6765\u9010\u4E2A\u5206\u6790\u4E0B\u8FD9\u51E0\u4E2A\u8FDB\u7A0B\u7684\u529F\u80FD\u3002</p><ul><li><strong>\u6D4F\u89C8\u5668\u8FDB\u7A0B</strong>\u3002\u4E3B\u8981\u8D1F\u8D23\u754C\u9762\u663E\u793A\u3001\u7528\u6237\u4EA4\u4E92\u3001\u5B50\u8FDB\u7A0B\u7BA1\u7406\uFF0C\u540C\u65F6\u63D0\u4F9B\u5B58\u50A8\u7B49\u529F\u80FD\u3002</li><li><strong>\u6E32\u67D3\u8FDB\u7A0B</strong>\u3002\u6838\u5FC3\u4EFB\u52A1\u662F\u5C06 HTML\u3001CSS \u548C JavaScript \u8F6C\u6362\u4E3A\u7528\u6237\u53EF\u4EE5\u4E0E\u4E4B\u4EA4\u4E92\u7684\u7F51\u9875\uFF0C\u6392\u7248\u5F15\u64CEBlink\u548CJavaScript\u5F15\u64CEV8\u90FD\u662F\u8FD0\u884C\u5728\u8BE5\u8FDB\u7A0B\u4E2D\uFF0C\u9ED8\u8BA4\u60C5\u51B5\u4E0B\uFF0CChrome\u4F1A\u4E3A\u6BCF\u4E2ATab\u6807\u7B7E\u521B\u5EFA\u4E00\u4E2A\u6E32\u67D3\u8FDB\u7A0B\u3002\u51FA\u4E8E\u5B89\u5168\u8003\u8651\uFF0C\u6E32\u67D3\u8FDB\u7A0B\u90FD\u662F\u8FD0\u884C\u5728\u6C99\u7BB1\u6A21\u5F0F\u4E0B\u3002</li><li><strong>GPU\u8FDB\u7A0B</strong>\u3002\u5176\u5B9E\uFF0CChrome\u521A\u5F00\u59CB\u53D1\u5E03\u7684\u65F6\u5019\u662F\u6CA1\u6709GPU\u8FDB\u7A0B\u7684\u3002\u800CGPU\u7684\u4F7F\u7528\u521D\u8877\u662F\u4E3A\u4E86\u5B9E\u73B03D CSS\u7684\u6548\u679C\uFF0C\u53EA\u662F\u968F\u540E\u7F51\u9875\u3001<strong>Chrome\u7684UI\u754C\u9762\u90FD\u9009\u62E9\u91C7\u7528GPU\u6765\u7ED8\u5236\uFF0C\u8FD9\u4F7F\u5F97GPU\u6210\u4E3A\u6D4F\u89C8\u5668\u666E\u904D\u7684\u9700\u6C42\u3002\u6700\u540E\uFF0CChrome\u5728\u5176\u591A\u8FDB\u7A0B\u67B6\u6784\u4E0A\u4E5F\u5F15\u5165\u4E86GPU\u8FDB\u7A0B</strong>\u3002</li><li><strong>\u7F51\u7EDC\u8FDB\u7A0B</strong>\u3002\u4E3B\u8981\u8D1F\u8D23\u9875\u9762\u7684\u7F51\u7EDC\u8D44\u6E90\u52A0\u8F7D\uFF0C\u4E4B\u524D\u662F\u4F5C\u4E3A\u4E00\u4E2A\u6A21\u5757\u8FD0\u884C\u5728\u6D4F\u89C8\u5668\u8FDB\u7A0B\u91CC\u9762\u7684\uFF0C\u76F4\u81F3\u6700\u8FD1\u624D\u72EC\u7ACB\u51FA\u6765\uFF0C\u6210\u4E3A\u4E00\u4E2A\u5355\u72EC\u7684\u8FDB\u7A0B\u3002</li><li><strong>\u63D2\u4EF6\u8FDB\u7A0B</strong>\u3002\u4E3B\u8981\u662F\u8D1F\u8D23\u63D2\u4EF6\u7684\u8FD0\u884C\uFF0C\u56E0\u63D2\u4EF6\u6613\u5D29\u6E83\uFF0C\u6240\u4EE5\u9700\u8981\u901A\u8FC7\u63D2\u4EF6\u8FDB\u7A0B\u6765\u9694\u79BB\uFF0C\u4EE5\u4FDD\u8BC1\u63D2\u4EF6\u8FDB\u7A0B\u5D29\u6E83\u4E0D\u4F1A\u5BF9\u6D4F\u89C8\u5668\u548C\u9875\u9762\u9020\u6210\u5F71\u54CD</li></ul><p>\u8BB2\u5230\u8FD9\u91CC\uFF0C\u73B0\u5728\u4F60\u5E94\u8BE5\u5C31\u53EF\u4EE5\u56DE\u7B54\u6587\u7AE0\u5F00\u5934\u63D0\u5230\u7684\u95EE\u9898\u4E86\uFF1A\u4EC5\u4EC5\u6253\u5F00\u4E861\u4E2A\u9875\u9762\uFF0C\u4E3A\u4EC0\u4E48\u67094\u4E2A\u8FDB\u7A0B\uFF1F\u56E0\u4E3A\u6253\u5F001\u4E2A<strong>\u9875\u9762\u81F3\u5C11\u9700\u89811\u4E2A\u7F51\u7EDC\u8FDB\u7A0B\u30011\u4E2A\u6D4F\u89C8\u5668\u8FDB\u7A0B\u30011\u4E2AGPU\u8FDB\u7A0B\u4EE5\u53CA1\u4E2A\u6E32\u67D3\u8FDB\u7A0B</strong>\uFF0C\u51714\u4E2A\uFF1B\u5982\u679C\u6253\u5F00\u7684\u9875\u9762\u6709\u8FD0\u884C\u63D2\u4EF6\u7684\u8BDD\uFF0C\u8FD8\u9700\u8981\u518D\u52A0\u4E0A<strong>1\u4E2A\u63D2\u4EF6\u8FDB\u7A0B\u3002</strong></p><p>\u4E0D\u8FC7\u51E1\u4E8B\u90FD\u6709\u4E24\u9762\u6027\uFF0C\u867D\u7136\u591A\u8FDB\u7A0B\u6A21\u578B\u63D0\u5347\u4E86\u6D4F\u89C8\u5668\u7684\u7A33\u5B9A\u6027\u3001\u6D41\u7545\u6027\u548C\u5B89\u5168\u6027\uFF0C\u4F46\u540C\u6837\u4E0D\u53EF\u907F\u514D\u5730\u5E26\u6765\u4E86\u4E00\u4E9B\u95EE\u9898</p><ul><li><strong>\u66F4\u9AD8\u7684\u8D44\u6E90\u5360\u7528</strong>\u3002\u56E0\u4E3A\u6BCF\u4E2A\u8FDB\u7A0B\u90FD\u4F1A\u5305\u542B\u516C\u5171\u57FA\u7840\u7ED3\u6784\u7684\u526F\u672C\uFF08\u5982JavaScript\u8FD0\u884C\u73AF\u5883\uFF09\uFF0C\u8FD9\u5C31\u610F\u5473\u7740\u6D4F\u89C8\u5668\u4F1A\u6D88\u8017\u66F4\u591A\u7684\u5185\u5B58\u8D44\u6E90\u3002</li><li><strong>\u66F4\u590D\u6742\u7684\u4F53\u7CFB\u67B6\u6784</strong>\u3002\u6D4F\u89C8\u5668\u5404\u6A21\u5757\u4E4B\u95F4\u8026\u5408\u6027\u9AD8\u3001\u6269\u5C55\u6027\u5DEE\u7B49\u95EE\u9898\uFF0C\u4F1A\u5BFC\u81F4\u73B0\u5728\u7684\u67B6\u6784\u5DF2\u7ECF\u5F88\u96BE\u9002\u5E94\u65B0\u7684\u9700\u6C42\u4E86</li></ul><p>\u5BF9\u4E8E\u4E0A\u9762\u8FD9\u4E24\u4E2A\u95EE\u9898\uFF0CChrome\u56E2\u961F\u4E00\u76F4\u5728\u5BFB\u6C42\u4E00\u79CD\u5F39\u6027\u65B9\u6848\uFF0C\u65E2\u53EF\u4EE5\u89E3\u51B3\u8D44\u6E90\u5360\u7528\u9AD8\u7684\u95EE\u9898\uFF0C\u4E5F\u53EF\u4EE5\u89E3\u51B3\u590D\u6742\u7684\u4F53\u7CFB\u67B6\u6784\u7684\u95EE\u9898</p><h3 id="\u672A\u6765\u9762\u5411\u670D\u52A1\u7684\u67B6\u6784" tabindex="-1"><a class="header-anchor" href="#\u672A\u6765\u9762\u5411\u670D\u52A1\u7684\u67B6\u6784" aria-hidden="true">#</a> \u672A\u6765\u9762\u5411\u670D\u52A1\u7684\u67B6\u6784</h3><p>\u4E3A\u4E86\u89E3\u51B3\u8FD9\u4E9B\u95EE\u9898\uFF0C\u57282016\u5E74\uFF0CChrome\u5B98\u65B9\u56E2\u961F\u4F7F\u7528**\u201C\u9762\u5411\u670D\u52A1\u7684\u67B6\u6784\u201D\uFF08Services Oriented Architecture\uFF0C\u7B80\u79F0SOA\uFF09**\u7684\u601D\u60F3\u8BBE\u8BA1\u4E86\u65B0\u7684Chrome\u67B6\u6784\u3002\u4E5F\u5C31\u662F\u8BF4 Chrome \u6574\u4F53\u67B6\u6784\u4F1A\u671D\u5411\u73B0\u4EE3\u64CD\u4F5C\u7CFB\u7EDF\u6240\u91C7\u7528\u7684\u201C\u9762\u5411\u670D\u52A1\u7684\u67B6\u6784\u201D \u65B9\u5411\u53D1\u5C55\uFF0C<strong>\u539F\u6765\u7684\u5404\u79CD\u6A21\u5757\u4F1A\u88AB\u91CD\u6784\u6210\u72EC\u7ACB\u7684\u670D\u52A1\uFF08Service\uFF09</strong>\uFF0C<strong>\u6BCF\u4E2A\u670D\u52A1\uFF08Service\uFF09\u90FD\u53EF\u4EE5\u5728\u72EC\u7ACB\u7684\u8FDB\u7A0B\u4E2D\u8FD0\u884C</strong>\uFF0C\u8BBF\u95EE\u670D\u52A1\uFF08Service\uFF09\u5FC5\u987B\u4F7F\u7528\u5B9A\u4E49\u597D\u7684\u63A5\u53E3\uFF0C\u901A\u8FC7IPC\u6765\u901A\u4FE1\uFF0C<strong>\u4ECE\u800C\u6784\u5EFA\u4E00\u4E2A\u66F4\u5185\u805A\u3001\u677E\u8026\u5408\u3001\u6613\u4E8E\u7EF4\u62A4\u548C\u6269\u5C55\u7684\u7CFB\u7EDF</strong>\uFF0C\u66F4\u597D\u5B9E\u73B0 Chrome \u7B80\u5355\u3001\u7A33\u5B9A\u3001\u9AD8\u901F\u3001\u5B89\u5168\u7684\u76EE\u6807\u3002\u5982\u679C\u4F60\u5BF9\u9762\u5411\u670D\u52A1\u7684\u67B6\u6784\u611F\u5174\u8DA3\uFF0C\u4F60\u53EF\u4EE5\u53BB\u7F51\u4E0A\u641C\u7D22\u4E0B\u8D44\u6599\uFF0C\u8FD9\u91CC\u5C31\u4E0D\u8FC7\u591A\u4ECB\u7ECD\u4E86\u3002</p><p>Chrome\u6700\u7EC8\u8981\u628AUI\u3001\u6570\u636E\u5E93\u3001\u6587\u4EF6\u3001\u8BBE\u5907\u3001\u7F51\u7EDC\u7B49\u6A21\u5757\u91CD\u6784\u4E3A\u57FA\u7840\u670D\u52A1\uFF0C\u7C7B\u4F3C\u64CD\u4F5C\u7CFB\u7EDF\u5E95\u5C42\u670D\u52A1\uFF0C\u4E0B\u9762\u662FChrome\u201C\u9762\u5411\u670D\u52A1\u7684\u67B6\u6784\u201D\u7684\u8FDB\u7A0B\u6A21\u578B\u56FE</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/329658fe821252db47b0964037a1de2a.png" alt="" loading="lazy"></p><p>\u76EE\u524DChrome\u6B63\u5904\u5728\u8001\u7684\u67B6\u6784\u5411\u670D\u52A1\u5316\u67B6\u6784\u8FC7\u6E21\u9636\u6BB5\uFF0C\u8FD9\u5C06\u662F\u4E00\u4E2A\u6F2B\u957F\u7684\u8FED\u4EE3\u8FC7\u7A0B\u3002</p><p>Chrome\u6B63\u5728\u9010\u6B65\u6784\u5EFAChrome\u57FA\u7840\u670D\u52A1\uFF08Chrome Foundation Service\uFF09\uFF0C\u5982\u679C\u4F60\u8BA4\u4E3AChrome\u662F\u201C\u4FBF\u643A\u5F0F\u64CD\u4F5C\u7CFB\u7EDF\u201D\uFF0C\u90A3\u4E48Chrome\u57FA\u7840\u670D\u52A1\u4FBF\u53EF\u4EE5\u88AB\u89C6\u4E3A\u8BE5\u64CD\u4F5C\u7CFB\u7EDF\u7684\u201C\u57FA\u7840\u201D\u7CFB\u7EDF\u670D\u52A1\u5C42\u3002</p><p>\u540C\u65F6Chrome\u8FD8\u63D0\u4F9B\u7075\u6D3B\u7684\u5F39\u6027\u67B6\u6784\uFF0C\u5728\u5F3A\u5927\u6027\u80FD\u8BBE\u5907\u4E0A\u4F1A\u4EE5\u591A\u8FDB\u7A0B\u7684\u65B9\u5F0F\u8FD0\u884C\u57FA\u7840\u670D\u52A1\uFF0C\u4F46\u662F\u5982\u679C\u5728\u8D44\u6E90\u53D7\u9650\u7684\u8BBE\u5907\u4E0A\uFF08\u5982\u4E0B\u56FE\uFF09\uFF0CChrome\u4F1A\u5C06\u5F88\u591A\u670D\u52A1\u6574\u5408\u5230\u4E00\u4E2A\u8FDB\u7A0B\u4E2D\uFF0C\u4ECE\u800C\u8282\u7701\u5185\u5B58\u5360\u7528\u3002</p><p><img src="https://mc-web-1259409954.cos.ap-guangzhou.myqcloud.com/MyImages/a9ba86d7b03263fa3997d3733d958176.png" alt="" loading="lazy"></p>',38);function t(n,s){return o}var g=r(e,[["render",t],["__file","L1.html.vue"]]);export{g as default};
